  "questionProse": [
    "इनमें से कौन सी PostgreSQL की सुविधा ANSI SQL मानक का हिस्सा नहीं है ❌ ?"
  ],
  "explanationProse": [
    "ANSI SQL के लिए PostgreSQL विस्तारों के उदाहरण:\n    - `RETURNING` क्लॉज़।\n    - `ILIKE` अक्षर-अनुप्रिया मिलान के लिए।\n    - सरणी प्रकार और संचालन।\n    - JSON/JSONB प्रकार।\n    \n    मूल ANSI SQL मानक में शामिल हैं:\n    - `WITH` (सामान्य तालिका अभिव्यक्ति)।\n    - `LIKE` पैटर्न मिलान के लिए।\n    - `LATERAL` जॉइन।\n    - विंडो फंक्शन।"
  ]
}
